package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;

class CSVFormatTest {

    @Test
    void testWithAllowMissingColumnNames() {
        CSVFormat original = CSVFormat.DEFAULT;
        assertFalse(original.getAllowMissingColumnNames());

        CSVFormat updated = original.withAllowMissingColumnNames();
        assertNotNull(updated);
        assertTrue(updated.getAllowMissingColumnNames());

        // The original instance should remain unchanged (immutability)
        assertFalse(original.getAllowMissingColumnNames());

        // Chaining multiple calls
        CSVFormat chained = updated.withAllowMissingColumnNames();
        assertTrue(chained.getAllowMissingColumnNames());
    }
}
